INSERT INTO public.photos VALUES (24041, 'Miguel Servet 1940', 'Imagen capturada en el patio del colegio de La Salle Montemolâ”śÂˇn, en su ubicaciâ”śâ”‚n entre el camino de las Torres y la calle de Miguel Servet, durante la inauguraciâ”śâ”‚n oficial de una lâ”śĂ­pida memorialista en recuerdo de los alumnos muertos, "Caâ”śÂˇdos por Dios y por Espaâ”śâ–’a en la Gloriosa Cruzada 1936-39". De izquierda a derecha, Antonio Gil, capellâ”śĂ­n del colegio; Joaquâ”śÂˇn de Pitarque, secretario provincial de FET-JONS; hermano Octavio Peâ”śâ–’a, director del colegio; Pâ”śÂˇo Altolaguirre, jefe provincial de FET-JONS; Josâ”śÂ® Mâ”¬Â¬ Arnau, presidente de la Diputaciâ”śâ”‚n Provincial de Teruel; Josâ”śÂ® Navarro Latorre, delegado provincial del SEU; y Santiago Eguâ”śÂˇa Aragâ”śâ”‚n, presidente nacional de los antiguos alumnos de La Salle. Fuente: www.todocoleccion.net/', 1940, 1940, 1940, 'Anos 40', 'SAN JOSâ”śĂ«', 41.64714000, -0.87386400, '0101000020E610000016DBA4A2B1F6EBBF7BF7C77BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30785947452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30785947452.webp', 'https://www.flickr.com/photos/zaragozaantigua/30785947452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24129, 'Exposiciâ”śâ”‚n aragonesa 1885', 'J. Thomas, 1885. En 1885 se inaugura el conjunto de edificios de lo que serâ”śĂ­ el nuevo Matadero Municipal, con el objeto provisional de albergar la Segunda Exposiciâ”śâ”‚n Regional Aragonesa. Fue encargado al arquitecto municipal Ricardo Magdalena. Estâ”śĂ­ situado en la carretera de Zaragoza a Castellâ”śâ”‚n, que corresponde al camino arbolado del primer plano del dibujo.', 1885, 1885, 1885, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64495400, -0.86960100, '0101000020E61000006534F279C5D3EBBF52B648DA8DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672382077.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672382077.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672382077/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24130, 'Miguel Servet 1885', 'Exposiciâ”śâ”‚n Aragonesa de 1885. Alzado y planta de la distribuciâ”śâ”‚n de los pabellones de la Exposiciâ”śâ”‚n, en lo que una vez terminada, serâ”śÂˇan las instalaciones del nuevo macelo municipal. Al sur, la "Carretera al Mediterrâ”śĂ­neo", o "Camino del Bajo Aragâ”śâ”‚n", mâ”śĂ­s tarde "Miguel Servet". Al Noroeste, el "Camino de las Fuentes", con su correspondiente acequia al aire, en lo que mucho mâ”śĂ­s tarde serâ”śÂˇa "Compromiso de Caspe". Al Norte (actual "Florentino Ballesteros") y al Este (actual ""Enrique Casas Vila"), "Salida a los Parques". Fuente visual: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1885, 1885, 1885, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64492700, -0.86952600, '0101000020E6100000BCB1A03028D3EBBF59A7CAF78CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16375046162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16375046162.webp', 'https://www.flickr.com/photos/zaragozaantigua/16375046162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24131, 'Expo 1885', 'Marcelino de Unceta, "Inauguraciâ”śâ”‚n de la Exposiciâ”śâ”‚n Regional Aragonesa: llegada del Emmo. Sr. Cardenal Benavides al local del concurso", 1885. En su calidad de arzobispo de la ciudad, el seâ”śâ–’or Francisco de Paula de Benavides y Fernâ”śĂ­ndez de Navarrete, llega al nuevo matadero sito en la carretera de Zaragoza a Castellâ”śâ”‚n, que hasta que entre en uso sirve de local del "concurso", o Expo de 1885. En la imagen, el carruaje del arzobispo junto a la reconocible y monumental puerta de entrada, representada sin las decorativas cabecicas de animales, las filigranas varias, y el escudo municipal. La inauguraciâ”śâ”‚n de esta exposiciâ”śâ”‚n se tuvo que retrasar al mes de octubre como consecuencia del brote de câ”śâ”‚lera de ese aâ”śâ–’o. Fuente visual: bdh.bne.es/ La Ilustraciâ”śâ”‚n Espaâ”śâ–’ola y Americana', 1885, 1885, 1885, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64456800, -0.87038700, '0101000020E610000038A27BD635DAEBBF2906483481D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16471129949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16471129949.webp', 'https://www.flickr.com/photos/zaragozaantigua/16471129949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24145, 'Exposiciâ”śâ”‚n Aragonesa 1885', '"Zaragoza. Inauguraciâ”śâ”‚n oficial del concurso: el presidente de la Sociedad Econâ”śâ”‚mica de Amigos del Paâ”śÂˇs pronunciando el discurso de apertura. Composiciâ”śâ”‚n y dibujo del natural por Marcelino de Unceta". Grabado que ilustra el comienzo de la Exposiciâ”śâ”‚n Aragonesa de 1885, celebrada en las dependencias del Matadero municipal de Zaragoza, antes de que este comenzase la actividad para la que fue edificado. Fuente: La ilustracâ”śâ”‚n espaâ”śâ–’ola y americana, Madrid, 8 de noviembre de 1885.', 1885, 1885, 1885, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64492700, -0.86952600, '0101000020E6100000BCB1A03028D3EBBF59A7CAF78CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21304859011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21304859011.webp', 'https://www.flickr.com/photos/zaragozaantigua/21304859011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24409, 'Colegio La Salle Montemolâ”śÂˇn c.1968', 'Vista parcial del conjunto del colegio La Salle Montemolâ”śÂˇn, desde su patio recayente al camino de las Torres. Fue levantado en 1916 segâ”śâ•‘n proyecto de Francisco Albiâ”śâ–’ana, junto a la ubicaciâ”śâ”‚n que ya ocupaban los hermanos de La Salle desde 1909. En 1929 se ampliâ”śâ”‚ y en 1972 se trasladâ”śâ”‚ a la calle Josâ”śÂ® Galiay, siendo derribado en 1973. Al fondo a la derecha, fragmento del nâ”śâ•‘mero 15 de la calle de Miguel Servet. Fuente visual: Jaime â”śĂĽlvarez Pâ”śÂ®rez de Labeaga, Josâ”śÂ® Antonio Noain Roncal, "Cien aâ”śâ–’os, gracias a ti. Colegio La Salle Montemolâ”śÂˇn, Zaragoza. 1909-2009".', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”śĂ«', 41.64706600, -0.87366100, '0101000020E61000000E4DD9E907F5EBBF412D060FD3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32023866564.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32023866564.webp', 'https://www.flickr.com/photos/zaragozaantigua/32023866564/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24420, 'Calle de Miguel Servet 1969', 'Imagen de la antigua "Carnicerâ”śÂˇa Casa Policeto", en la luminosa calle del Miguel Servet nâ”¬â•‘ 28, esquina con el camino de las Torres nâ”¬â•‘ 171 (a la derecha), alquilada por Policeto Lobera a los hermanos de las Escuelas Cristianas y remodelada para abrir un Colegio que denominaron de Nuestra Seâ”śâ–’ora del Pilar en 1909, al que ellos coloquialmente se referâ”śÂˇan como "la casa vulgar y fea", o "la caja de cerillas" del suburbio de Montemolâ”śÂˇn. Allâ”śÂˇ se impartâ”śÂˇa educaciâ”śâ”‚n cristiana para niâ”śâ–’os pobres, y clases nocturnas diarias y catequesis los domingos para adultos. Detrâ”śĂ­s de esta fachada habâ”śÂˇa un patio interior utilizado como zona de recreo, y la acequia de San Josâ”śÂ® bajaba al aire inmediata a la parte recayente al camino de las Torres (a la derecha) En 1916 construirâ”śĂ­n un colegio de nueva planta, mucho mâ”śĂ­s grande y espacioso, al otro lado del camino de las Torres, que en 1929, y tras una destacable ampliaciâ”śâ”‚n, fue redenominado La Salle Montemolâ”śÂˇn, siendo derribado en 1973 tras el traslado a una nueva ubicaciâ”śâ”‚n mâ”śĂ­s amplia en la calle de Josâ”śÂ® Galiay, junto a la antigua Granja Agrâ”śÂˇcola de Zaragoza. Esta casa fue derribada al poco de capturar la imagen, y sobre parte de ella se ampliâ”śâ”‚ en anchura el camino de las Torres para trâ”śĂ­nsito rodado. A la izquierda, el bloque del actual nâ”¬â•‘ 44 de la calle de Miguel Servet. Al fondo, el bloque del actual nâ”¬â•‘ 7 del camino de las Torres. Fuente visual: Jaime â”śĂĽlvarez Pâ”śÂ®rez de Labeaga, Josâ”śÂ® Antonio Noain Roncal, "Cien aâ”śâ–’os, gracias a ti. Colegio La Salle Montemolâ”śÂˇn, Zaragoza. 1909-2009".', 1969, 1969, 1969, 'Anos 60', 'SAN JOSâ”śĂ«', 41.64682300, -0.87302500, '0101000020E61000008FE4F21FD2EFEBBF7AA69718CBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34901838711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34901838711.webp', 'https://www.flickr.com/photos/zaragozaantigua/34901838711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24451, 'Matadero Municipal 1887', 'Postal. Archivo y Hemeroteca Municipales de Zaragoza, 1887. Interior del pabellâ”śâ”‚n central de matacâ”śÂˇa de carneros y vacas del Matadero Municipal de la calle Miguel Servet de Zaragoza, hoy Centro Câ”śÂˇvico Salvador Allende. Proyecto de "Macelo Municipal" de Ricardo Magdalena, aprobado en 1877 y construido entre 1878 y 1885, aâ”śâ–’o en que albergâ”śâ”‚ la Exposiciâ”śâ”‚n Aragonesa. Comenzâ”śâ”‚ su actividad como matadero en 1887. Fuente: "Ricardo Magdalena. Arquitecto municipal de Zaragoza". IFC, 2012.', 1887, 1887, 1887, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64492700, -0.86952600, '0101000020E6100000BCB1A03028D3EBBF59A7CAF78CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15355507357.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15355507357.webp', 'https://www.flickr.com/photos/zaragozaantigua/15355507357/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24460, 'Avenida de San Josâ”śÂ® 1978', 'Imagen del tramo inaugural de la avenida de San Josâ”śÂ®. A la izquierda, el frontal hasta la calle Miraflores, con el edificio donde estuvo ubicada la Antigua fâ”śĂ­brica de GIESA (Guiral Industrias Elâ”śÂ®ctricas S.A.), antes de su traslado en 1946 a la calle Miguel Servet. Posteriormente, estas serâ”śÂˇan las instalaciones de la fâ”śĂ­brica de muebles "Abenia". Al fondo, las HH. de los Ancianos Desamparados ya habâ”śÂˇan perpetrado la reforma de la fachada y el acceso desde la avenida, aunque aâ”śâ•‘n no habâ”śÂˇan derribado el pabellâ”śâ”‚n de las Hermanas Enfermas. Fuente visual: "La evoluciâ”śâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1978, 1978, 1978, 'Anos 70', 'SAN JOSâ”śĂ«', 41.64402300, -0.87283300, '0101000020E610000080D3BB783FEEEBBF976F7D586FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19773221214.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19773221214.webp', 'https://www.flickr.com/photos/zaragozaantigua/19773221214/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24485, 'Matadero c.1904', 'Fototipia para postal editada por "El Ciclâ”śâ”‚n", pasaje comercial, nâ”¬â•‘ 40 (Garcâ”śÂˇa, Paraâ”śÂˇso y Ariz-Navarreta) como parte de una serie denominada "Zaragoza". Este nuevo Matadero municipal, sito en la antigua carretera de Alcaâ”śâ–’iz, fue obra de Ricardo Magdalena, y terminado en 1884. Se estrenâ”śâ”‚ como recinto de la Exposiciâ”śâ”‚n Aragonesa de 1885. En la imagen, puerta de acceso al patio que articulaba los pabellones principales, con vista de la original fuente del Buen Pastor, obra de Dionisio Lausâ”śÂ®n en 1885. Fuente visual: www.delcampe.net/', 1904, 1904, 1904, 'Anos 1900', 'SAN JOSâ”śĂ«', 41.64456800, -0.87038700, '0101000020E610000038A27BD635DAEBBF2906483481D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23934521862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23934521862.webp', 'https://www.flickr.com/photos/zaragozaantigua/23934521862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24493, 'Calle de Miguel Servet c.1982', 'Imagen capturada desde cierta altura (posiblemente el nâ”¬â•‘ 84 de la calle de Miguel Servet) y centrada en el ingreso principal y patio central que vertebraba los pabellones del antiguo macelo municipal. En el centro del porticado espacio destaca la circular impronta donde estuviera la pâ”śÂ®trea fuente del Buen Pastor, realizada por Dionisio Lasuâ”śÂ®n, removida de su original ubicaciâ”śâ”‚n tras el cierre del matadero y trasladada al lustroso paseo de Marina Moreno, redenominado de la Constituciâ”śâ”‚n tras la recuperaciâ”śâ”‚n de la democracia municipal en 1979. Al fondo, edificios de la avenida del Compromiso de Caspe y de la calle de Jorge Cocci. Fuente visual: AMZ.', 1982, 1982, 1982, 'Anos 80', 'SAN JOSâ”śĂ«', 41.64453300, -0.87025000, '0101000020E61000000C022B8716D9EBBFAD18AE0E80D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27113279497.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27113279497.webp', 'https://www.flickr.com/photos/zaragozaantigua/27113279497/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24500, 'Matadero 1901', 'Imagen del matadero municipal, en la carretera del Bajo Aragâ”śâ”‚n, que fuera sede de la Exposiciâ”śâ”‚n Aragonesa de 1885. El pabellâ”śâ”‚n central de la imagen, que confronta con la entrada principal, fue entonces el espacio del muestrario industrial. En el momento de realizar la captura, notable trâ”śĂ­fico en el patio interior del macelo originado por vehâ”śÂˇculos de reparto y distribuciâ”śâ”‚n, tras cargar las piezas procesadas. Fuente visual: Josep Maria Reitg Martâ”śÂˇ, Ajuntament de Girona.', 1901, 1901, 1901, 'Anos 1900', 'SAN JOSâ”śĂ«', 41.64477600, -0.87006000, '0101000020E61000002BD9B11188D7EBBF739F1C0588D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31010343073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31010343073.webp', 'https://www.flickr.com/photos/zaragozaantigua/31010343073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24524, 'Ctra. de Castellâ”śâ”‚n c.1902', 'Imagen capturada desde el principio del camino de Cabaldâ”śâ”‚s y centrada en el Matadero municipal ubicado en la carretera de Zaragoza a Castellâ”śâ”‚n entre el huerto de Valls y la torre de Castâ”śĂ­n (izquierda), el camino de las Fuentes y el riego de la Reja (al fondo), y la torre de Aladrâ”śÂ®n y el campo de Higuera (derecha). Sobre el firme, vâ”śÂˇas de la lâ”śÂˇnea tranviaria del Bajo Aragâ”śâ”‚n. Fuente visual: www.ebay.es/', 1902, 1902, 1902, 'Anos 1900', 'SAN JOSâ”śĂ«', 41.64453300, -0.87025000, '0101000020E61000000C022B8716D9EBBFAD18AE0E80D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39907125931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39907125931.webp', 'https://www.flickr.com/photos/zaragozaantigua/39907125931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24529, 'Ctra. de Castellâ”śâ”‚n c.1895', 'Inâ”śÂ®dita imagen capturada en la calle de tierra y sin nombre que conectaba la carretera de Zaragoza a Castellâ”śâ”‚n, luego calle de Miguel Servet, con las traseras de la Torre de Ascaso, luego de Guillâ”śÂ®n, el Molino del Seminario y una hijuela al aire de la acequia de Las Adulas, o de San Josâ”śÂ®. A la derecha, inmueble esquinero con el arranque del camino de Cabaldâ”śâ”‚s, hacia la derecha y fuera de plano, tambiâ”śÂ®n denominado camino del Frontâ”śâ”‚n por conducir al reciâ”śÂ®n inaugurado Frontâ”śâ”‚n Zaragozano. Apoyada sobre su esquina, a la solana, un moderno vehâ”śÂˇculo para la prâ”śĂ­ctica del deporte velocipâ”śÂ®dico. Al fondo, la monumental puerta de ingreso al moderno macelo municipal, donde posa una interesante galerâ”śÂˇa de tancredos. Tras la verja, el patio central de los pabellones, con la estatua del Buen Pastor en su centro.', 1895, 1895, 1895, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64442400, -0.87052700, '0101000020E6100000A81E69705BDBEBBFF660527C7CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48018802802.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48018802802.webp', 'https://www.flickr.com/photos/zaragozaantigua/48018802802/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24530, 'Avenida de San Josâ”śÂ® 1937', 'Luminosa imagen capturada en la avenida de San Josâ”śÂ® y centrada en el inmueble del nâ”¬â•‘ 32, esquinero con la calle de Miraflores, a la derecha, donde Joaquâ”śÂˇn Guiral estableciâ”śâ”‚ la tercera de las ubicaciones en la ciudad de sus talleres de construcciones electromagnâ”śÂ®ticas. Este destacable edificio, anteriormente albergâ”śâ”‚ los talleres de muebles de La Catedral del Mueble de Urbano Bernardos, y con el recrecimiento posterior de una altura perdurarâ”śÂˇa con diversos usos hasta los aâ”śâ–’os 80, cuando fue derribado para dar paso a modernos bloques de viviendas. Pocos aâ”śâ–’os mâ”śĂ­s tarde, y tras la constituciâ”śâ”‚n de la empresa Guiral Industrial Elâ”śÂ®ctricas S.A. (Giesa), una cuarta localizaciâ”śâ”‚n darâ”śÂˇa cabida a un nuevo, moderno, y mucho mâ”śĂ­s grande complejo fabril en la calle de Miguel Servet. La arbolada avenida de la imagen fue podada luego con motivo del establecimiento del tendido de la tranviaria lâ”śÂˇnea nâ”¬â•‘ 13. San Josâ”śÂ®, inaugurada en agosto de 1945.', 1937, 1937, 1937, 'Anos 30', 'SAN JOSâ”śĂ«', 41.64401500, -0.87284400, '0101000020E61000007A50508A56EEEBBF159161156FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48382539126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48382539126.webp', 'https://www.flickr.com/photos/zaragozaantigua/48382539126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24539, 'Miguel Servet c.1919', 'Imagen comercializada como postal de la serie "Zaragoza", y titulada "Portada del Matadero", municipal instalaciâ”śâ”‚n diseâ”śâ–’ada por Ricardo Magdalena Tabuenca y terminada en 1884 que se estrenâ”śâ”‚ como recinto de la Exposiciâ”śâ”‚n Aragonesa de 1885. Esta monumental entrada daba acceso al patio central que articulaba los pabellones principales, donde fluâ”śÂˇa la original fuente del Buen Pastor, obra de Dionisio Lausâ”śÂ®n en 1885, visible al fondo. Hacia la derecha y fuera de plano, comenzaba el antiguo camino de Cabaldâ”śâ”‚s, llamado en su primer tramo camino del Frontâ”śâ”‚n por conducir al Frontâ”śâ”‚n Zaragozano allâ”śÂˇ ubicado.', 1919, 1919, 1919, 'Anos 10', 'SAN JOSâ”śĂ«', 41.64456000, -0.87045100, '0101000020E6100000E7A7380EBCDAEBBFA6272CF180D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51327607793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51327607793.webp', 'https://www.flickr.com/photos/zaragozaantigua/51327607793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21323, 'Cartuja de Aula Dei c.1900', 'Dibujo de la Cartuja de Nuestra Seâ”śâ–’ora de Aula Dei con una perspectiva aâ”śÂ®rea del gran conjunto, levantado entre el camino de Peâ”śâ–’aflor de Gâ”śĂ­llego, hacia la izquierda, y el homâ”śâ”‚nimo râ”śÂˇo, que serpentea a la derecha. En 1564 se puso la primera piedra del conjunto, con el favor polâ”śÂˇtico y patrocinio del arzobispo Hernando de Aragâ”śâ”‚n, con un primer nâ”śâ•‘cleo de nueve frailes cartujos. En 1835 el inmueble fue desamortizado, y dos aâ”śâ–’os despuâ”śÂ®s fue adquirido por Juan Francisco Clarac, que destinâ”śâ”‚ el recinto a fâ”śĂ­brica de sedas. Durante el resto del siglo XIX cambiâ”śâ”‚ de propietario varias veces. En 1903 la Orden cartujana fue regresada a estas dependencias. El amurallado recinto aparece vertebrado en torno a tres patios. El mayor, a la izquierda, ordenaba las 36 celdas o viviendas de los moradores. A la derecha e inmediato, un camino arbolado lleva a gran entrada que conduce primero a la hospederâ”śÂˇa y la procura, para dar paso luego a la iglesia y torre barroca.', 1900, 1900, 1900, 'Anos 1900', NULL, 41.73228300, -0.81255900, '0101000020E61000003E4162BB7B00EABF59350873BBDD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48149996957.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48149996957.webp', 'https://www.flickr.com/photos/zaragozaantigua/48149996957/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24693, 'Matadero Miguel Servet 1956', 'Hay sol, pero el mercurio dice "menos 5 grados". Y sin cierzo. Tres maestros matarifes del Macelo Municipal (Mariano Martâ”śÂˇnez, Mariano Dâ”śÂˇez, y Manuel Lâ”śâ”‚pez), capturados en inestable equilibrio sobre el agua helada, de habitual lâ”śÂˇquida, a los pies de la estatua "El buen pastor", obra de Dionisio Lasuâ”śÂ®n que desde 1885 centraba la plaza principal del nuevo Matadero de Zaragoza, sito en Miguel Servet, obra de Ricardo Magdalena. Estos matarifes formaban parte importante del proceso por el que los semovientes que ingresaban (o eran hechos ingresar) por una puerta, salieran por otra encarrilados hacia una pronta ingesta. Cuando este Matadero fue clausurado, a mediados de los aâ”śâ–’os 70 del pasado siglo, la estatua fue movilizada hasta el actual paseo de la Constituciâ”śâ”‚n, donde una infausta noche de junio de 2002 unos homâ”śÂˇnidos se encaramaron por ella y la derribaron, si bien se precipitâ”śâ”‚ sin pretenderlo sobre uno de los que estaban abajo de miranda, con tal fortuna que al infortunado se le tuvo que amputar un brazo. La estatua quedâ”śâ”‚ hecha pedazos. De resultas de ello, se encargâ”śâ”‚ una fiel reproducciâ”śâ”‚n del original, realizada por Frank Norton, y que en 2006 fue colocada en el original emplazamiento de la original estatua. El original estâ”śĂ­ en la nave-biblioteca del Centro Câ”śÂˇvico Salvador Allende, que asâ”śÂˇ es como se denomina ahora este espacio.', 1956, 1956, 1956, 'Anos 50', 'SAN JOSâ”śĂ«', 41.64472800, -0.86995300, '0101000020E6100000AAD381ACA7D6EBBF6268757286D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850779554.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850779554.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850779554/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24694, 'Calle Miguel Servet 1925', 'La imagen se ha podido capturar desde el â”śâ•‘ltimo piso del nâ”¬â•‘ 41 de Miguel Servet (actual nâ”¬â•‘ 61), un edificio de 4 plantas de finales del s.XIX que ha sobrevivido y ha llegado a nuestros dâ”śÂˇas como vestigio del antiguo Camino del Bajo Aragâ”śâ”‚n. En la esquina inferior derecha, el edificio de las escuelas de Montemolâ”śÂˇn, o Grupo Escolar Tomâ”śĂ­s Alvira (aâ”śâ•‘n en pie). Tras la calle de las Escuelas (actual Numancia), el complejo del Macelo municipal. Al otro lado de Miguel Servet, un poco mâ”śĂ­s adelante de donde estâ”śĂ­ el tranvâ”śÂˇa, hacia la izquierda, el comienzo del Camino de Cabaldâ”śâ”‚s, que al poco llegaba al Frontâ”śâ”‚n Zaragozano. Tambiâ”śÂ®n es visible la esquina del callejâ”śâ”‚n del Pilar (luego calle Matadero) que desemboca en Miguel Servet.', 1925, 1925, 1925, 'Anos 20', 'SAN JOSâ”śĂ«', 41.64396500, -0.86983000, '0101000020E6100000BD8C62B9A5D5EBBF6362F3716DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15277413984.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15277413984.webp', 'https://www.flickr.com/photos/zaragozaantigua/15277413984/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24696, 'Compromiso de Caspe 1981', 'Foto Montse Grao, septiembre de 1981. Fiestas del barrio de Las Fuentes. Desfile de majorettes por la avenida del Compromiso de Caspe, con Miguel Servet al fondo. A la izquierda, casa y solar que pronto serâ”śĂ­n reemplazados por el gran edificio del nâ”śâ•‘mero 6. A la derecha, la calle Joaquâ”śÂˇn Sanz Gadea. Fuente: www.facebook.com/photo.php?fbid=10152538813987961&set...', 1981, 1981, 1981, 'Anos 80', 'SAN JOSâ”śĂ«', 41.64608800, -0.87090200, '0101000020E6100000F7AB00DF6DDEEBBF452BF702B3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15480521506.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15480521506.webp', 'https://www.flickr.com/photos/zaragozaantigua/15480521506/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24698, 'Compromiso de Caspe 1978', 'Imagen de una pintura mural realizada por el "Colectivo Plâ”śĂ­stico de Zaragoza", titulada "Aragâ”śâ”‚n 23 de Abril: Ganemos la Autonomâ”śÂˇa". Caracterâ”śÂˇstica del proceso de la "Transiciâ”śâ”‚n" y recuperaciâ”śâ”‚n de la democracia de finales de los aâ”śâ–’os 70 del pasado siglo, fue la exaltaciâ”śâ”‚n del regionalismo como otro campo de lucha contra el franquismo, que parecâ”śÂˇa no haberse disuelto milagrosamente tras la muerte de Francisco Franco. En marzo de 1978 un real decreto ley del gobierno de Espaâ”śâ–’a instituyâ”śâ”‚ la Diputaciâ”śâ”‚n General de Aragâ”śâ”‚n, y el 23 de abril de ese aâ”śâ–’o, como "dâ”śÂˇa de nuestro seâ”śâ–’or San Jorge", los 18 primeros diputados autonâ”śâ”‚micos (elegidos indirectamente, sin elecciones ad hoc), escenificaron en la Catedral de Huesca la elecciâ”śâ”‚n del primer Gobierno de Aragâ”śâ”‚n. Mientras, en Zaragoza tenâ”śÂˇa lugar una manifestaciâ”śâ”‚n multitudinaria, por algunas de las calles mâ”śĂ­s significadas de la ciudad. Unos dâ”śÂˇas antes, por encargo del aâ”śâ•‘n no oficial Gobierno de Aragâ”śâ”‚n, este "Colectivo Plâ”śĂ­stico de Zaragoza" realizâ”śâ”‚ cuatro murales con el institucional lema "Ganemos la Autonomâ”śÂˇa", en ubicaciones de la avenida de Madrid, del paseo del General Mola (esquina con la calle Zumalacâ”śĂ­rregui), de la calle San Juan de la Peâ”śâ–’a, y este que ilustra la entrada, en la manzana de casas entre Miguel Servet y Compromiso de Caspe. Este "Colectivo Plâ”śĂ­stico de Zaragoza", que habâ”śÂˇa nacido para reivindicar peticiones sociales, se encontrâ”śâ”‚ realizando estos murales como encargo oficial, con un lema que no significa absolutamente nada, y casualmente fueron sus â”śâ•‘ltimas producciones. El mural desapareciâ”śâ”‚, como el muro que lo soportaba. En su lugar mâ”śĂ­s tarde se levantarâ”śÂˇan los bloques de los nâ”śâ•‘meros 4-6-8 de Compromiso de Caspe. Fuente visual: "Historia contemporâ”śĂ­nea de Aragâ”śâ”‚n. Dos siglos cruciales, del XIX al XX", HA, 1993. Fuente textual: Mâ”¬Â¬ Luisa Grau Tello, "La calle es nuestra: la pintura mural del Colectivo Plâ”śĂ­stico de Zaragoza durante la Transiciâ”śâ”‚n", 2012.', 1978, 1978, 1978, 'Anos 70', 'SAN JOSâ”śĂ«', 41.64608800, -0.87090200, '0101000020E6100000F7AB00DF6DDEEBBF452BF702B3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18958406284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18958406284.webp', 'https://www.flickr.com/photos/zaragozaantigua/18958406284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24700, 'Matadero municipal 1901', 'El matadero municipal de Zaragoza, obra de Ricardo Magdalena, fue inaugurado en la carretera de Castellâ”śâ”‚n como sede de la Exposiciâ”śâ”‚n Aragonesa de 1885 y entrâ”śâ”‚ en funcionamiento funcional, para los propâ”śâ”‚sitos de su construcciâ”śâ”‚n, en 1887. Al fondo, el Pilar. Fuente visual: "Arquitectura y Construcciâ”śâ”‚n" (Barcelona).', 1901, 1901, 1901, 'Anos 1900', 'SAN JOSâ”śĂ«', 41.64396500, -0.86983000, '0101000020E6100000BD8C62B9A5D5EBBF6362F3716DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20925028498.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20925028498.webp', 'https://www.flickr.com/photos/zaragozaantigua/20925028498/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24714, 'Cine Roxy 1987', 'El cine Roxy, en la calle de Miguel Servet 53, fue inaugurado el 1 de febrero de 1961. Fue un cine de reestreno con 500 localidades, construido segâ”śâ•‘n proyecto de Josâ”śÂ® Beltrâ”śĂ­n. Cerrâ”śâ”‚ en agosto de 1985 y el edificio fue demolido en julio de 1987, como muestra la foto. Al fondo, traseras del nâ”śâ•‘mero 18 de la avenida del Compromiso de Caspe, recayentes a la calle del Monasterio de Samos.', 1987, 1987, 1987, 'Anos 80', 'SAN JOSâ”śĂ«', 41.64525900, -0.87099100, '0101000020E6100000DF87838428DFEBBF8F39CFD897D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54388932253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54388932253.webp', 'https://www.flickr.com/photos/zaragozaantigua/54388932253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24849, 'Quinta de San Josâ”śÂ® c.1900', 'Cortejo fâ”śâ•‘nebre ante la fachada de la Quinta de San Josâ”śÂ®, famosa sobre todo por el gran vivero de â”śĂ­rboles frutales y plantas y â”śĂ­rboles ornamentales que desde los aâ”śâ–’os ochenta del siglo XIX pertenecâ”śÂˇa a la familia Cambra, situado al principio del camino de San Josâ”śÂ®, confrontando con el despartidero donde la calle de Miguel Servet prosigue hacia la carretera de Castellâ”śâ”‚n (a la derecha y fuera de plano). Las traseras de esta quinta llegaban hasta el camino de las Torres, y desapareciâ”śâ”‚ cuando la zona fue reurbanizada da forma radical con motivo de la apertura de la calle de la Reina Fabiola.', 1900, 1900, 1900, 'Anos 1900', 'SAN JOSâ”śĂ«', 41.64619500, -0.87237200, '0101000020E61000008D463EAF78EAEBBF5BEB8B84B6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21001811588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21001811588.webp', 'https://www.flickr.com/photos/zaragozaantigua/21001811588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25197, 'Puente sobre el Huerva 1847', '"Proyecto de un puente colgado que se intenta construir sobre el râ”śÂˇo Huerva en el sitio denominado de San Josâ”śÂ® Estramuros de la Ciudad de Zaragoza". Antonio de Ibarrarun, Graus, 1847. En el plano se refleja la iglesia del convento de San Josâ”śÂ®, la ubicaciâ”śâ”‚n de la Puerta Quemada y el lugar pretendido para levantar el puente colgante (no realizado), junto a los "caminos de ronda de la poblaciâ”śâ”‚n": la actual calle del Asalto, que ha conservado el nombre popular de Ronda hasta nuestros dâ”śÂˇas. Fuente: Archivo Municipal de Zaragoza.', 1847, 1847, 1847, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64818500, -0.87202200, '0101000020E6100000758F6CAE9AE7EBBFFE60E0B9F7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30485877366.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30485877366.webp', 'https://www.flickr.com/photos/zaragozaantigua/30485877366/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25583, 'Fâ”śĂ­brica de regaliz 1899', 'Vista de las traseras de la fâ”śĂ­brica de regaliz de Zaragoza Carenou y Tur, levantada en 1874 como Flor, Cardenou y Tur. Sita en la calle Asalto 23, hoy El Aaiâ”śâ•‘n. Comercializaron la marca Zara. Fuente: Mâ”¬Â¬ Pilar Biel Ibâ”śĂ­â”śâ–’ez, Zaragoza y la industrializaciâ”śâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1899, 1899, 1899, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64852000, -0.87132000, '0101000020E610000019390B7BDAE1EBBFA5660FB402D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19613741298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19613741298.webp', 'https://www.flickr.com/photos/zaragozaantigua/19613741298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25589, 'Siâ”śÂżge de Saragosse 1809', 'Maqueta de hacia 1810, que representa la Zaragoza destruida por los Sitios en 1809. Este conjunto urbano imaginado podrâ”śÂˇa rememorar el entorno del convento de los carmelitas de San Josâ”śÂ®, en primer plano, derruido y utilizado como fuerte defensivo, con foso incluido. Ante â”śÂ®l, una de las trincheras paralelas realizadas por los franceses en su aproximaciâ”śâ”‚n, durante el asedio de 1809. Junto a â”śÂ®l, el puente de San Josâ”śÂ® y el râ”śÂˇo Huerva, y detrâ”śĂ­s, el muro de rejola desde la puerta Quemada, hasta el molino de aceite de la ciudad. Fuente visual: www.museedesplansreliefs.culture.fr/', 1809, 1809, 1809, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64734600, -0.87205800, '0101000020E6100000A8E2C62DE6E7EBBF2499D53BDCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30879118465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30879118465.webp', 'https://www.flickr.com/photos/zaragozaantigua/30879118465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25592, 'Puente de San Josâ”śÂ® 1839', 'Dibujo incluido en el proyecto "para el puente llamado de San Josâ”śÂ® sobre el râ”śÂˇo Huerva" realizado por los arquitectos Josâ”śÂ® de Yarza y Joaquâ”śÂˇn Gironza para el Ayuntamiento. Este puente estaba previsto en la misma ubicaciâ”śâ”‚n "donde estaba el antiguo arruinado" durante los asedios franceses de 1808-09, y para sustituir al provisional que en 1838 se llevâ”śâ”‚ por delante una salida de madre del râ”śÂˇo, que tambiâ”śÂ®n destruyâ”śâ”‚ el puente de Santa Engracia. El dibujo muestra cierta fidelidad de este proyecto con el puente de piedra construido en el siglo XVI. Desde la izquierda se accede por el camino de la Puerta Quemada y la ronda que enlaza con las Tenerâ”śÂˇas y la Puerta del Sol, y hacia la derecha arranca la carretera del Bajo Aragâ”śâ”‚n junto al ex-convento de San Josâ”śÂ®. Este proyecto no serâ”śÂˇa llevado a cabo, y finalmente un puente provisional y en madera (mâ”śĂ­s barato) serâ”śÂˇa ubicado unas decenas de metros aguas arriba. En los aâ”śâ–’os cincuenta y durante las obras vinculadas a la apertura de la plaza de San Miguel hacia el sur, se proyectarâ”śÂˇa un nuevo puente en piedra, en una nueva ubicaciâ”śâ”‚n y definitiva aguas arriba, que abrirâ”śÂˇa la nueva vâ”śÂˇa de comunicaciâ”śâ”‚n hacia el sureste con una nueva puerta (del Duque de la Victoria) y su correspondiente caseta de consumos.', 1839, 1839, 1839, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64791900, -0.87250100, '0101000020E61000000246973787EBEBBF80BA8102EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50061496367.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50061496367.webp', 'https://www.flickr.com/photos/zaragozaantigua/50061496367/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25733, 'Convento de San Josâ”śÂ® 1860', 'Esta imagen aparece en el libro "Primeros tiempos de la fotografâ”śÂˇa en Zaragoza", datada equivocadamente como "Convento de las Fecetas", pues se trata del antiguo Convento de San Josâ”śÂ® de los Carmelitas Descalzos, fundado en 1594 junto al camino del Bajo Aragâ”śâ”‚n, en la ribera derecha del râ”śÂˇo Huerva, extramuros de la ciudad. Arruinado e incendiado durante la guerra de 1808-1809, quedâ”śâ”‚ muy daâ”śâ–’ado. Fue reconstruido en 1814, y en 1835 fue desamortizado y estatalizado, ejerciendo de presidio hasta 1900, como "Penal de San Josâ”śÂ®". En 1908 fue reconvertido a cuartel de Intendencia, hasta el aâ”śâ–’o 1971, en que fue incluido en la "Operaciâ”śâ”‚n Cuarteles", y vendido al Ayuntamiento, que lo derribâ”śâ”‚ unos aâ”śâ–’os despuâ”śÂ®s para prolongar el camino de las Torres hasta el Ebro, y hacer zonas verdes y otros viales. En la imagen, vista del antiguo convento, cuando era Penal. A la derecha, al fondo, la torre de San Miguel de los Navarros. Por este lugar pasa, en la actualidad, el camino de las Torres un poco antes del cruce con Jorge Cocci. Fuente visual: Mariano Jâ”śâ•‘dez y Ortiz, 1859-1860. Col. Mariano Martâ”śÂˇn Casalderrey.', 1860, 1860, 1860, 'Siglo XIX', 'SAN JOSâ”śĂ«', 41.64755000, -0.87221100, '0101000020E61000003FC4060B27E9EBBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20240961111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20240961111.webp', 'https://www.flickr.com/photos/zaragozaantigua/20240961111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25740, 'Asilo de San Josâ”śÂ® 1945', 'Imagen de la avenida de San Josâ”śÂ® a la altura del Asilo de las Hermanas de los Pobres. Diseâ”śâ–’ado en 1882 en formas neomedievales, historicistas y eclâ”śÂ®cticas, por Ricardo Magdalena. Una posterior reforma del edificio adosarâ”śĂ­ a la planta calle, de acceso, todo un nuevo pabellon-pegote que a Magdalena no le hubiera hecho pizca gracia. El adoquinado de la avenida se habâ”śÂˇa llevado por delante los â”śĂ­rboles que mojoneaban el antiguo camino. Los postes de madera sostienen el cableado del tranvâ”śÂˇa de la novâ”śÂˇsima lâ”śÂˇnea 13 "San Josâ”śÂ®". La fotografâ”śÂˇa se ha realizado desde una de las parcelas enfrente al Asilo, ya desaparecidas todas ellas. Fuente visual: AHPZ, Archivo Coyne', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”śĂ«', 41.64503300, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF9EEBFB7090D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20322661276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20322661276.webp', 'https://www.flickr.com/photos/zaragozaantigua/20322661276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25742, 'Avenida de San Josâ”śÂ® 1990', 'En setiembre de 1879, Pilar Garcâ”śÂˇa Fulla de Ubirâ”śÂˇa, regalâ”śâ”‚ a la Congregaciâ”śâ”‚n de las Hermanitas de los Ancianos Desamparados un magnâ”śÂˇfico campo con riego de la acequia de las Adulas, en el camino de San Josâ”śÂ®, para construir un internado de ancianos desvalidos. Ricardo Magdalena proyectâ”śâ”‚ el inmueble, que fue inaugurado el 24 de mayo de 1882. El complejo ha padecido numerosas modificaciones y ampliaciones que lo han desvirtuado parcialmente. Una de las mutaciones mâ”śĂ­s impactantes implicâ”śâ”‚ el derribo del Pabellâ”śâ”‚n-Sanatorio de las Hermanitas Enfermas, situado cerca de la esquina con la calle Miraflores. Con este derribo, se perdiâ”śâ”‚ el eclecticismo modernista de inspiraciâ”śâ”‚n neomedieval de este curioso edificio, singularmente concentrado en el poderoso torreâ”śâ”‚n. Fuente visual: Historia y poblaciâ”śâ”‚n del barrio de San Josâ”śÂ® (Zaragoza), 2004.', 1990, 1990, 1990, 'Anos 90', 'SAN JOSâ”śĂ«', 41.64439100, -0.87290800, '0101000020E61000002A560DC2DCEEEBBF1A6B7F677BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20355457456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20355457456.webp', 'https://www.flickr.com/photos/zaragozaantigua/20355457456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25743, 'Avenida de San Josâ”śÂ® 1948', 'Imagen del tranvâ”śÂˇa nâ”¬â•‘ 90 (reactualizaciâ”śâ”‚n de una unidad mâ”śĂ­s antigua de la serie 20) de la Lâ”śÂˇnea 13 en la Avenida de Josâ”śÂ® a la altura del Asilo de Pobres. Fuente: "Los tranvâ”śÂˇas de Zaragoza", J. Peâ”śâ–’a - J. M. Valero, DPZ, 1985.', 1948, 1948, 1948, 'Anos 40', 'SAN JOSâ”śĂ«', 41.64503300, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF9EEBFB7090D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20357745772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20357745772.webp', 'https://www.flickr.com/photos/zaragozaantigua/20357745772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25751, 'Elecciones 1977', 'Foto Luis Mompel, 1977. Jueves 16 de junio de 1977. En Espaâ”śâ–’a se celebran elecciones generales, prâ”śĂ­ctica cuya anterior convocatoria tuvo lugar en febrero de 1936. En la imagen, un grupo de electores hacen fila en la entrada de la residencia de San Josâ”śÂ® de las Hermanitas de los Ancianos Desamparados, vulgo Hermanitas de los Pobres, en la avenida de San Josâ”śÂ® 22. Fuente: Archivo Heraldo de Aragâ”śâ”‚n.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”śĂ«', 41.64503300, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF9EEBFB7090D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20571913841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20571913841.webp', 'https://www.flickr.com/photos/zaragozaantigua/20571913841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25768, 'Miguel Servet 1977', 'Calle de Miguel Servet en una imagen centrada en el tramo entre la del Monasterio de Samos y el punto donde, al fondo, arrancan la avenida de San Josâ”śÂ®, la del Compromiso de Caspe, y la calle de la Reina Fabiola. Perdura en el firme el histâ”śâ”‚rico tendido tranviario que hasta febrero de 1976 servâ”śÂˇa para conducir a las unidades de la lâ”śÂˇnea 11. Parque-San Josâ”śÂ® hasta las cocheras situadas mâ”śĂ­s allâ”śĂ­ de de la plaza de Utrillas. La fotografâ”śÂˇa muestra que la supresiâ”śâ”‚n de los tranvâ”śÂˇas no fue un â”śÂ®xito a la hora de fluidificar el trâ”śĂ­fico y mejorar la movilidad viaria. La masiva presencia de vehâ”śÂˇculos a motor incluye el caracterâ”śÂˇstico aparcamiento en baterâ”śÂˇa, y el trâ”śĂ­nsito de vehâ”śÂˇculos de mâ”śĂ­s de 8 Tm por esta calle, considerada por la Ordenanzas Municipales de circulaciâ”śâ”‚n como vâ”śÂˇa de trâ”śĂ­fico interurbano y acceso a sectores industriales desde la carretera de Castellâ”śâ”‚n.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”śĂ«', 41.64555600, -0.87144800, '0101000020E6100000784485EAE6E2EBBF48DE3994A1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33056621345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33056621345.webp', 'https://www.flickr.com/photos/zaragozaantigua/33056621345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25775, 'Av. de San Josâ”śÂ® 1977', 'Imagen del primer tramo de la avenida de San Josâ”śÂ® capturada desde la esquina con la calle del Fuero del Trabajo. Al fondo, el arranque desde la avenida del Compromiso de Caspe, cuyas parcelas eclipsan levemente al modernâ”śÂˇsimo Hâ”śĂ­bitat Don 2000. A la izquierda, e inmediato, el luminoso del cine Dux, cerrado en mayo. A la derecha, muro perimetral, edificios y â”śĂ­rboles de la antigua Torre Fraile, luego desaparecida. A ambos lados de la avenida perduran los gruesos postes del desmantelado tendido elâ”śÂ®ctrico de la lâ”śÂˇnea 11 del tranvâ”śÂˇa, clausurada un aâ”śâ–’o antes. Los autobuses de la lâ”śÂˇnea 40 realizan el mismo trayecto, de forma mâ”śĂ­s moderna. Fuente visual: revista "Aragâ”śâ”‚n turâ”śÂˇstico y monumental", SIPA.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”śĂ«', 41.64371000, -0.87273700, '0101000020E6100000F94A202576EDEBBFD80DDB1665D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34672611971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34672611971.webp', 'https://www.flickr.com/photos/zaragozaantigua/34672611971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25776, 'C.â”¬â•‘ de Cabaldâ”śâ”‚s 1929', 'Imagen del interior del recinto deportivo del Frontâ”śâ”‚n Zaragozano poco antes de ser inauguradas las reformas de esta veterana instalaciâ”śâ”‚n abierta en 1895. En la soleada zona de la contracancha, inmediata a la zona de gradas descubiertas, destaca la puerta de acceso desde las taquillas ubicadas en el arranque del camino de Cabaldâ”śâ”‚s, muy cerca de la calle de Miguel Servet, donde una parada de la tranviaria lâ”śÂˇnea del Bajo Aragâ”śâ”‚n le proporcionaba buena conexiâ”śâ”‚n desde el centro de la ciudad. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'SAN JOSâ”śĂ«', 41.64391800, -0.87039800, '0101000020E6100000321F10E84CDAEBBF22A7AFE76BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35068619802.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35068619802.webp', 'https://www.flickr.com/photos/zaragozaantigua/35068619802/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25792, 'Av. de San Josâ”śÂ® 1977', 'Vista parcial del muro que delimitaba los restos de la antigua Torre de Fraile localizada en el tramo de la avenida entre las calles Matadero y Privilegio de la Uniâ”śâ”‚n. Aâ”śâ–’os mâ”śĂ­s tarde, sobre parte de esta torre se trazarâ”śÂˇa la plaza de la Reina Sofâ”śÂˇa.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”śĂ«', 41.64340700, -0.87279300, '0101000020E6100000F3AFE595EBEDEBBF3D821B295BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54395866955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54395866955.webp', 'https://www.flickr.com/photos/zaragozaantigua/54395866955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26003, 'Cuartel de San Josâ”śÂ® 1968', 'Vista en altura del râ”śÂˇo Huerva aguas abajo del puente de San Josâ”śÂ®, centrada en el Cuartel de Intendencia nâ”¬â•‘ 5 del ejâ”śÂ®rcito de tierra (antiguo convento y prisiâ”śâ”‚n). En la margen izquierda del râ”śÂˇo, el tambiâ”śÂ®n militar "Parque", o "Corral de la Leâ”śâ–’a", y el reciente complejo de Elâ”śÂ®ctricas Reunidas de Zaragoza. En la margen derecha, almacenes y solares de las traseras de Miguel Servet, calle que llega, al fondo, hasta el gran partidero hacia San Josâ”śÂ®, las Fuentes, y la carretera de Castellâ”śâ”‚n. Junto al cuartel, la calle del Conde Alperche conectaba con Miguel Servet y el Camino de las Torres. El original y medieval puente de San Josâ”śÂ® sobre el Huerva estuvo ubicado cerca de la esquina del convento mâ”śĂ­s inmediata a nosotros. Por allâ”śÂˇ estaba trazado, entonces, el antiguo y principal camino de Fuentes, Mediana, y Tortosa. Cuando este puente fue destruido durante los conflictos 1808-1809, su ubicaciâ”śâ”‚n fue cambiando, hasta llegar a la actual, unos pocos cientos de metros aguas arriba, cerca de la iglesia de San Miguel. Aâ”śâ–’os mâ”śĂ­s tarde, tras la primera "Operaciâ”śâ”‚n Cuarteles", esta instalaciâ”śâ”‚n cuartelaria serâ”śÂˇa desmilitariazada, y derribada. El entorno comenzarâ”śÂˇa a cambiar radicalmente.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”śĂ«', 41.64755000, -0.87221100, '0101000020E61000003FC4060B27E9EBBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22168868028.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22168868028.webp', 'https://www.flickr.com/photos/zaragozaantigua/22168868028/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26031, 'Vista aâ”śÂ®rea Miguel Servet 1963', 'Vista aâ”śÂ®rea desde la calle de Miguel Servet, con el complejo del Matadero Municipal, y el resto de la ciudad, hasta el Ebro y mâ”śĂ­s allâ”śĂ­. Fuente: TAF Helicâ”śâ–“pters. Arxiu Nacional de Catalunya.', 1963, 1963, 1963, 'Anos 60', 'SAN JOSâ”śĂ«', 41.64453300, -0.87025000, '0101000020E61000000C022B8716D9EBBFAD18AE0E80D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30539218524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30539218524.webp', 'https://www.flickr.com/photos/zaragozaantigua/30539218524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23367, 'Barranco del Paso del Ganado 1833', '"El Barranco del Paso del Ganado", litografâ”śÂˇa de Faramundo Blanchard. El Canal Imperial de Aragâ”śâ”‚n prosigue demediado su curso hacia el Este, y a la altura de La Cartuja de la Concepciâ”śâ”‚n salva un barranco mediante la obra mostrada, que subsiste, entre las Esclusas de Valmadrid y la Almenara de La Concepciâ”śâ”‚n. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', NULL, 41.58019400, -0.78656000, '0101000020E6100000B3EF8AE07F2BE9BFEFAA07CC43CA4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19308049000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19308049000.webp', 'https://www.flickr.com/photos/zaragozaantigua/19308049000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21214, 'Canal Imperial 1900', '1900. Gâ”śâ”‚ndola "Sta. Cecilia" en un posado en el embarcadero de la Quinta Julieta Sagols, que queda a la izquierda. Al fondo, la pronunciada curva del Canal hacia la derecha para dirigirse al puente-acueducto del Barranco de la Muerte, por donde originalmente pasaba el Canal. En la actualidad, unas biondas que quitan el miedo tratan de evitar que los coches caigan al Canal. Los peatones, mientras tanto, juegan a la pista (norte)americana para evitar ser atropellados. En 2003 se desviâ”śâ”‚ el Canal y se construyâ”śâ”‚ una nueva estructura sobre el Tercer Cinturâ”śâ”‚n mâ”śĂ­s hacia la izquierda, por donde en la actualidad el Canal supera el barranco. El cisne tallado en la proa, al modo y manera de las gâ”śâ”‚ndolas venecianas, aun abatido y un tanto taciturno, acabâ”śâ”‚ por apropiarse con el nomenclâ”śĂ­tor de la embarcaciâ”śâ”‚n, y la santa de la mâ”śâ•‘sica, los poetas, y los ciegos, apenas es recordada. Aquâ”śÂˇ lo hacemos.', 1900, 1900, 1900, 'Anos 1900', 'SAN JOSâ”śĂ«', 41.62570800, -0.87143800, '0101000020E610000095BBCFF1D1E2EBBF3C6C223317D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085398726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085398726.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085398726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21249, 'Quinta Julieta c.1900', 'Postal de "Quinta Julieta" circulada el aâ”śâ–’o 1907, cuando era lugar de acceso pâ”śâ•‘blico (pagando una entrada) como lugar donde pasar el domingo junto al Canal Imperial con un espectâ”śĂ­culo de "macizos verdes, amarillos, arcos de rosales trepadores", de "flores, estanques y cisnes, glorietas, madreselvas, câ”śÂ®sped, cenadores". Fuente visual: postal Hauser y Menet serie "Zaragoza", nâ”¬â•‘ 2005, en www.todocoleccion.net/', 1900, 1900, 1900, 'Anos 1900', 'SAN JOSâ”śĂ«', 41.62527500, -0.87090200, '0101000020E6100000F7AB00DF6DDEEBBFD200DE0209D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20307535522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20307535522.webp', 'https://www.flickr.com/photos/zaragozaantigua/20307535522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21327, 'Quinta Julieta 1900', 'Dibujo de la tribuna de pâ”śâ•‘blico del campo de tiro habilitado en la canalina Quinta Julieta, cedida para la ocasiâ”śâ”‚n por su propietario Enrique Sagols y Ferrer durante la celebraciâ”śâ”‚n del primer certamen nacional de tiro, organizado por la Asociaciâ”śâ”‚n del Tiro Nacional en el marco de las Fiestas del Pilar de 1900, entre los dâ”śÂˇas 17 y 21 de octubre.', 1900, 1900, 1900, 'Anos 1900', 'SAN JOSâ”śĂ«', 41.62538700, -0.87025800, '0101000020E6100000C2A2224E27D9EBBFFA2B64AE0CD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50074123163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50074123163.webp', 'https://www.flickr.com/photos/zaragozaantigua/50074123163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21332, 'Quinta Julieta 1900', 'Entrega de premios en el primer certamen nacional de tiro, organizado por la Asociaciâ”śâ”‚n del Tiro Nacional en el marco de las Fiestas del Pilar de 1900, entre los dâ”śÂˇas 17 y 21 de octubre. El campo de tiro fue habilitado en la Quinta Julieta, cedida para la ocasiâ”śâ”‚n por su propietario Enrique Sagols y Ferrer, cuya casa aparece en esta imagen como fondo escâ”śÂ®nico para la ceremonia de entrega de premio de las tres categorâ”śÂˇas habilitadas: obreros, jornaleros y trabajadores; estudiantes; y oficiales del ejâ”śÂ®rcito.', 1900, 1900, 1900, 'Anos 1900', 'SAN JOSâ”śĂ«', 41.62531500, -0.87065500, '0101000020E6100000062AE3DF67DCEBBF605969520AD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50923005947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50923005947.webp', 'https://www.flickr.com/photos/zaragozaantigua/50923005947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21411, 'Quinta Julieta c.1918', 'Curiosa imagen de la finca conocida como "Quinta Julieta", cuando tras los tiempos de las gâ”śâ”‚ndolas por el Canal y su acceso pâ”śâ•‘blico, los actos deportivos, y las renombradas fiestas y celebraciones en el marco de la exposiciâ”śâ”‚n Hispano-Francesa de 1908, ya era propiedad de los PP. Jesuitas como dependencia ultraperifâ”śÂ®rica del Colegio del Salvador. Con ediciâ”śâ”‚n de â”śĂĽngel Toldrâ”śĂ­ Viazo, en Barcelona, se realizâ”śâ”‚ entonces una serie de postales alusiva a este colegio, entre las que se encontraba esta vista denominada "Las colmenas de la Quinta Julieta".', 1918, 1918, 1918, 'Anos 10', 'SAN JOSâ”śĂ«', 41.62527500, -0.87090200, '0101000020E6100000F7AB00DF6DDEEBBFD200DE0209D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27595454721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27595454721.webp', 'https://www.flickr.com/photos/zaragozaantigua/27595454721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21546, 'La Granja 1922', 'Imagen de los jardines y huertos que flanqueaban el ingreso a los pabellones principales de la desaparecida Granja Agrâ”śÂˇcola de Zaragozal. Al fondo, clarea el monumento a Manuel Rodrâ”śÂˇguez Ayuso, que fuera impulsor y director de esta Granja. Detrâ”śĂ­s del edificio de los establos, moreras del camino luego redenominado calle de Josâ”śÂ® Galiay. Fuente visual: Archivo Requejo, AHPZ-DARA.', 1922, 1922, 1922, 'Anos 20', 'SAN JOSâ”śĂ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20182158289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20182158289.webp', 'https://www.flickr.com/photos/zaragozaantigua/20182158289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21554, 'Barrio de la Paciencia 1929', 'Imagen capturada en la calle de Carbâ”śâ”‚ y centrada en un muro que delimitaba una propiedad que hacâ”śÂˇa de tapâ”śâ”‚n en esta calle que vertebraba el denominado barrio de la Paciencia, y que poco despuâ”śÂ®s fue derribado para facilitar el trâ”śĂ­nsito. Este barrio fue creado en 1928 y era otro ejemplo de barrio-calle a ambos lados de un largo y nuevo vial denominado calle Carbâ”śâ”‚ (primer tramo) y calle Grao (segundo tramo), nombres de las parcelaciones que estos propietarios emprendieron en dos terrenos que llegaban desde el camino de San Josâ”śÂ® hasta el de Cabaldâ”śâ”‚s. Aâ”śâ–’os mâ”śĂ­s tarde, esta calle recibirâ”śĂ­ una sola denominaciâ”śâ”‚n comâ”śâ•‘n: Uniâ”śâ”‚n, y tras 1940, Privilegio de la Uniâ”śâ”‚n. La razâ”śâ”‚n que explicaba una aislada urbanizaciâ”śâ”‚n como esta, en un entorno despoblado, es que quienes vivâ”śÂˇan en las 50 parcelas que componâ”śÂˇan este barrio particular, unos 250 vecinos en total, trabajaban y dependâ”śÂˇan de un taller de fundiciâ”śâ”‚n y una fâ”śĂ­brica de mosaicos cercanos. El barrio habâ”śÂˇa nacido al calor de estas factorâ”śÂˇas. El desorden urbanâ”śÂˇstico, la ausencia de equipamientos, la escasa calidad de los edificios (autoconstruidos con materiales de la zona), y una importante cantidad de acequias y riegos al aire, caracterizaban a esta zona, tal y como le pasaba a otros "barrios particulares" que luego conformarâ”śĂ­n el barrio de San Josâ”śÂ®: barrio de San Josâ”śÂ® de Calasanz, Comâ”śÂˇn, Monforte, Cuber, Colâ”śâ”‚n, los Chiflaos... La foto actualmente se corresponderâ”śÂˇa con el tramo de los nâ”śâ•‘meros impares de la calle del Privilegio de la Uniâ”śâ”‚n entre las del Monasterio de Samos y Santa Rosa.', 1929, 1929, 1929, 'Anos 20', 'SAN JOSâ”śĂ«', 41.64254700, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF4B92E7FA3ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21179745292.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21179745292.webp', 'https://www.flickr.com/photos/zaragozaantigua/21179745292/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23368, 'Almenara de La Concepciâ”śâ”‚n 1833', '"Almenara de La Concepciâ”śâ”‚n", litografâ”śÂˇa de Faramundo Blanchard. Tras pasar el Barranco de Las Casetas, en el punto en que se halla esta almenara, prâ”śâ”‚ximo a La Cartuja de la Concepciâ”śâ”‚n, el Canal Imperial abandona su curso primitivo y se transforma en una red de acequias que llega por El Burgo de Ebro (cuyos campos riega la acequia que parte de esta Almenara) hasta Fuentes de Ebro. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', NULL, 41.57942800, -0.78449600, '0101000020E610000059F8FA5A971AE9BF7F315BB22ACA4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19308299060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19308299060.webp', 'https://www.flickr.com/photos/zaragozaantigua/19308299060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21973, 'Campo del Arenas 1944', 'El club Arenas S.D. de "football" fue fundado en 1927, y en 1941, tras pasar por La Cartuja, el velâ”śâ”‚dromo de los Campos Eliseos, la Hâ”śÂˇpica y San Gregorio, contâ”śâ”‚ con terreno de juego propio en el nuevo Campo de San Josâ”śÂ®, construido sobre antiguos campos de cultivo del Barrio de la Paciencia, entre el Camino de San Josâ”śÂ® y el de Cabaldâ”śâ”‚s, y las calles Carbâ”śâ”‚ y Castelar, a unas pocas decenas de metros del Frontâ”śâ”‚n Zaragozano. En â”śÂ®l jugaban tambiâ”śÂ®n como locales equipos que no se podâ”śÂˇan permitir tener campo propio, como el Club Atlâ”śÂ®tico Zaragoza. Este terreno de juego fue derribado en 1967, y urbanizado inmediatamente. En la imagen, saludo fascista preceptivo antes del comienzo de la sâ”śÂ®ptima jornada de la liga 1944-45 (Tercera Divisiâ”śâ”‚n, Grupo 4) entre el Club Atlâ”śÂ®tico Zaragoza (camiseta blanca y pantalâ”śâ”‚n azul claro) y La Sociedad Deportiva Escoriaza (camiseta roja y pantalâ”śâ”‚n negro), en el campo de San Josâ”śÂ®, el 5 de noviembre de 1944. Venciâ”śâ”‚ el Atlâ”śÂ®tico por dos tantos a cero. Tras las parcelas del fondo, la larga calle Uniâ”śâ”‚n (antigua Carbâ”śâ”‚), y las pequeâ”śâ–’as calles de General Ricardos, y del Salvador. Fuente visual: Gerardo Sancho Ramo, Archivo Pâ”śâ•‘blico Municipal.', 1944, 1944, 1944, 'Anos 40', 'SAN JOSâ”śĂ«', 41.64145100, -0.87096500, '0101000020E610000090BDDEFDF1DEEBBF467EFD101BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24231521250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24231521250.webp', 'https://www.flickr.com/photos/zaragozaantigua/24231521250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
